INSERT INTO audit_point (`id`, `dim_id`, `name`, `category`, `desc`, `risk_points`, `examples`, `default_result`, `default_checked`, `status`, `sort_order`) VALUES
(1, 1, '主体信息与签署授权', '合规与权属风险', '核查甲乙方名称、统一社会信用代码、法定代表人与授权是否完整一致', '[{"title":"主体信息缺失","clauseNote":"","high":"主体信息或授权材料缺失将导致责任主体难以确认。","low":"主体信息表述不完整，建议补充核对。"}]', '[]', '{"clause":"","model":"","overview":"主体信息或签署授权不完整，可能影响合同效力与追责。","solution":"补充双方主体信息、统一社会信用代码、法定代表人和授权文件。"}', 1, '已启用', 10),
(2, 1, '标的范围与服务边界', '权利义务失衡', '标的、服务范围与交付物边界是否清晰', '[{"title":"服务边界不清","clauseNote":"","high":"标的范围不清会导致验收和责任边界争议。","low":"服务范围需进一步细化交付物。"}]', '[]', '{"clause":"","model":"","overview":"标的范围和服务边界不明确，容易引发履约争议。","solution":"明确服务范围、交付物清单、验收标准和排除事项。"}', 1, '已启用', 20),
(3, 3, '价格、发票与付款条件', '权利义务失衡', '价格、付款节点、比例与发票约定是否对我方不利', '[{"title":"付款条件风险","clauseNote":"","high":"付款节点或发票约定缺失可能造成资金和税务风险。","low":"付款比例和开票时点需要细化。"}]', '[]', '{"clause":"","model":"","overview":"价格、付款和发票约定不清，可能造成回款或税务处理风险。","solution":"明确付款节点、支付时限、发票类型、税率和逾期责任。"}', 1, '已启用', 30),
(4, 2, '交付计划与验收机制', '履约保障不足', '识别默示验收等对我方不利的验收条款', '[{"title":"默示验收风险","clauseNote":"","high":"默示验收可能导致质量问题被默认接受。","low":"验收程序和标准需进一步明确。"}]', '[]', '{"clause":"","model":"","overview":"交付计划和验收机制不明确，可能导致自动验收或整改争议。","solution":"约定书面验收、明确验收标准、整改期限和复验流程。"}', 1, '已启用', 40),
(5, 2, '质量保证与售后服务', '履约保障不足', '质保期、响应时限与售后责任是否明确', '[{"title":"售后保障不足","clauseNote":"","high":"质保责任和响应时限缺失会削弱履约保障。","low":"售后服务标准需细化。"}]', '[]', '{"clause":"","model":"","overview":"质量保证和售后服务标准不够明确。","solution":"补充质保期、响应时限、服务等级和违约责任。"}', 1, '已启用', 50),
(6, 2, '知识产权与成果归属', '合规与权属风险', '成果、数据与衍生知识产权归属是否清晰', '[{"title":"权属不清","clauseNote":"","high":"成果和数据归属不清可能导致后续使用受限。","low":"授权范围和使用边界需细化。"}]', '[]', '{"clause":"","model":"","overview":"知识产权和成果归属表述笼统，后续授权、使用和商业化可能产生争议。","solution":"明确成果、数据、衍生成果的权属和许可范围。"}', 1, '已启用', 60),
(7, 2, '数据安全与保密义务', '合规与权属风险', '数据安全、保密范围与期限是否完备', '[{"title":"保密义务缺失","clauseNote":"","high":"保密范围和数据安全义务缺失可能造成合规风险。","low":"保密期限和例外需要完善。"}]', '[]', '{"clause":"","model":"","overview":"数据安全和保密义务不完整，可能导致敏感信息保护不足。","solution":"补充保密范围、期限、例外、数据安全措施和违约责任。"}', 1, '已启用', 70),
(8, 2, '违约责任与赔偿上限', '履约保障不足', '违约金比例、赔偿上限是否足以覆盖损失', '[{"title":"赔偿上限过低","clauseNote":"","high":"过低赔偿上限可能不足以覆盖实际损失。","low":"违约责任条款需要与损失匹配。"}]', '[]', '{"clause":"","model":"","overview":"违约责任或赔偿上限过低，会削弱违约约束力。","solution":"提高违约金和赔偿上限，补充重大违约解除权。"}', 1, '已启用', 80),
(9, 2, '合同解除与退出机制', '权利义务失衡', '解除条件、退出与善后安排是否对等', '[{"title":"解除机制不对等","clauseNote":"","high":"解除条件不对等会影响我方退出权。","low":"善后义务和费用结算需明确。"}]', '[]', '{"clause":"","model":"","overview":"合同解除和退出机制不够清晰，可能影响违约场景下的处置。","solution":"明确解除条件、通知期限、善后安排和费用结算。"}', 1, '已启用', 90),
(10, 2, '法律适用与争议解决', '权利义务失衡', '管辖、仲裁与法律适用是否对我方有利', '[{"title":"争议解决不利","clauseNote":"","high":"不利管辖会增加维权成本。","low":"争议解决条款需要明确唯一方式。"}]', '[]', '{"clause":"","model":"","overview":"法律适用和争议解决约定不明确或不利。","solution":"明确适用法律、管辖法院或仲裁机构。"}', 1, '已启用', 100),
(11, 3, '需求变更与费用调整', '履约保障不足', '变更流程与相应费用调整机制是否清晰', '[{"title":"变更费用风险","clauseNote":"","high":"需求变更无费用调整机制可能导致成本失控。","low":"变更审批流程需细化。"}]', '[]', '{"clause":"","model":"","overview":"需求变更和费用调整机制不明确。","solution":"约定书面变更、审批流程、费用调整和工期顺延。"}', 1, '已启用', 110),
(12, 4, '附件完整性与签章形式', '合规与权属风险', '附件、签字盖章、份数与生效条件是否完整', '[{"title":"签章附件不完整","clauseNote":"","high":"附件或签章缺失可能影响文本完整性和效力。","low":"份数和骑缝章要求需明确。"}]', '[]', '{"clause":"","model":"","overview":"附件和签章形式约定不完整。","solution":"补充附件清单、签章页、骑缝章和合同份数。"}', 1, '已启用', 120),
(13, 3, '发票与费用承担', '权利义务失衡', '税费、发票类型与开具时点约定是否明确', '[{"title":"发票税费风险","clauseNote":"","high":"发票类型或税费承担缺失会影响税务处理。","low":"开票时点需与付款条件衔接。"}]', '[]', '{"clause":"","model":"","overview":"发票与税费承担约定不完整。","solution":"明确发票类型、税率、开具时点和税费承担。"}', 1, '已启用', 130),
(14, 2, '不可抗力处理', '履约保障不足', '不可抗力情形、通知与责任免除是否合理', '[{"title":"不可抗力处理不清","clauseNote":"","high":"通知和减损义务缺失可能扩大争议。","low":"不可抗力范围需与法律规定衔接。"}]', '[]', '{"clause":"","model":"","overview":"不可抗力处理流程不够完整。","solution":"明确不可抗力范围、通知期限、证明材料和减损义务。"}', 1, '已启用', 140),
(15, 2, '转包与分包限制', '合规与权属风险', '是否限制擅自转包、分包及相应责任', '[{"title":"转分包风险","clauseNote":"","high":"擅自转包分包会增加履约和合规风险。","low":"第三方责任承担需明确。"}]', '[]', '{"clause":"","model":"","overview":"转包与分包限制不明确。","solution":"禁止未经书面同意转包分包，并约定第三方责任。"}', 1, '已启用', 150),
(16, 2, '保密期限与范围', '合规与权属风险', '保密信息范围、期限与例外是否清晰', '[{"title":"保密范围不清","clauseNote":"","high":"保密范围和期限缺失可能导致商业秘密保护不足。","low":"保密例外和披露流程需完善。"}]', '[]', '{"clause":"","model":"","overview":"保密期限与范围不够清晰。","solution":"明确保密信息范围、期限、例外情形和违约责任。"}', 1, '已启用', 160),
(17, 3, '结算与对账方式', '履约保障不足', '结算周期、对账确认与争议处理是否明确', '[{"title":"结算对账风险","clauseNote":"","high":"对账确认机制缺失可能造成回款争议。","low":"结算资料和争议处理需细化。"}]', '[]', '{"clause":"","model":"","overview":"结算与对账方式不明确。","solution":"明确结算周期、对账确认、异议期限和争议处理。"}', 1, '已启用', 170),
(18, 4, '通知与送达条款', '权利义务失衡', '通知方式、送达地址与生效时点是否完备', '[{"title":"送达条款风险","clauseNote":"","high":"通知送达不明会影响解除、索赔等权利行使。","low":"送达地址和变更通知需明确。"}]', '[]', '{"clause":"","model":"","overview":"通知与送达条款不够完备。","solution":"明确通知方式、送达地址、变更通知和生效时点。"}', 0, '已停用', 180);
